import React from 'react';

const Projects = () => {
  return (
    <section id="projects" className="section">
      <div className="container">
        <h2>Featured Projects</h2>
        <div className="projects-grid">
          <div className="project-card">
            <h3>Green Bridge Design</h3>
            <p>Designed a sustainable pedestrian bridge using recycled materials, reducing carbon footprint by 30%.</p>
          </div>
          <div className="project-card">
            <h3>Urban Water Management System</h3>
            <p>Implemented a rainwater harvesting system for a mixed-use development, saving 1.2M gallons annually.</p>
          </div>
          <div className="project-card">
            <h3>Seismic Retrofit of Historic Building</h3>
            <p>Led structural analysis and retrofitting of a 1920s building to meet modern earthquake standards.</p>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Projects;
